function ResNetAnalysisPage({ onNavigateBack }) {
    const [selectedImage, setSelectedImage] = useState(null);
    const [scanning, setScanning] = useState(false);
    const [scanProgress, setScanProgress] = useState(0);
    const [result, setResult] = useState(null);
    const fileInputRef = useRef(null);

    const handleImageUpload = (e) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            const reader = new FileReader();
            reader.onload = (ev) => {
                setSelectedImage({
                    src: ev.target.result,
                    size: file.size, // bytes
                    name: file.name
                });
                setResult(null);
            };
            reader.readAsDataURL(file);
        }
    };

    const startAnalysis = () => {
        if (!selectedImage) return;

        setScanning(true);
        setScanProgress(0);
        setResult(null);

        // Robotic Voice Activation
        const utterance = new SpeechSynthesisUtterance("Initiating ResNet-18 Neural Scan. Extracting Features.");
        utterance.rate = 1.0;
        utterance.pitch = 0.8;
        utterance.volume = 1.0;
        window.speechSynthesis.speak(utterance);

        let progress = 0;
        const interval = setInterval(() => {
            progress += 2;
            setScanProgress(progress);

            if (progress >= 100) {
                clearInterval(interval);
                setTimeout(() => {
                    setScanning(false);
                    calculateEmission();
                }, 500);
            }
        }, 60); // Total ~3 seconds
    };

    const calculateEmission = () => {
        // Pseudo-science calculation for simulation
        // 18 Layers of ResNet * Image Size Factor * Energy Coeff
        const pixels = selectedImage.size; // Using file size as entropy proxy
        const complexityFactor = 18; // ResNet-18
        const energyPerBit = 0.00000015; // J/bit estimated
        const totalEnergyJ = (pixels * 8) * complexityFactor * energyPerBit; // Joules
        const carbonIntensity = 475; // gCO2/kWh (average grid)
        const energyKWh = totalEnergyJ / 3600000;
        const carbonG = energyKWh * carbonIntensity;

        const synthFinish = new SpeechSynthesisUtterance("Analysis Complete. Carbon Footprint Calculated.");
        synthFinish.rate = 1.0;
        synthFinish.pitch = 0.8;
        window.speechSynthesis.speak(synthFinish);

        setResult({
            co2: carbonG.toFixed(6),
            energy: totalEnergyJ.toFixed(4),
            layers: 18,
            status: 'OPTIMIZED'
        });
    };

    return (
        <div style={{ background: 'var(--bg-primary)', minHeight: '100vh', position: 'relative', overflowX: 'hidden' }}>
            <div className="scanline"></div>

            <div className="container" style={{ paddingTop: '40px', paddingBottom: '60px' }}>
                {/* Header */}
                <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' }}>
                    <button
                        onClick={onNavigateBack}
                        className="robotic-btn"
                        style={{
                            padding: '12px 24px',
                            background: 'rgba(0, 210, 255, 0.05)',
                            border: '1px solid var(--robotic-blue)',
                            color: '#fff',
                            borderRadius: '4px',
                            cursor: 'pointer',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '10px'
                        }}
                    >
                        <span>«</span> [ TERMINATE_MODULE ]
                    </button>
                    <h2 style={{ fontSize: '1.5rem', color: 'var(--robotic-blue)', fontFamily: 'var(--terminal-font)' }}>
                        MODULE: ResNet-18_CNN
                    </h2>
                </header>

                {/* Educational Section */}
                <div className="glass-card" style={{ padding: '30px', marginBottom: '40px', borderLeft: '4px solid var(--accent-orange)' }}>
                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: '40px', flexWrap: 'wrap' }}>
                        <div style={{ flex: 1, minWidth: '300px' }}>
                            <h3 style={{ fontSize: '1.4rem', color: '#fff', marginBottom: '20px' }}>🔹 Neural Architecture: ResNet-18</h3>
                            <ul style={{ listStyle: 'none', padding: 0, lineHeight: 1.8, color: 'var(--text-secondary)' }}>
                                <li style={{ marginBottom: '10px' }}>
                                    <strong style={{ color: 'var(--accent-blue)' }}>Purpose:</strong> Deep CNN for Image Classification & Computer Vision.
                                </li>
                                <li style={{ marginBottom: '10px' }}>
                                    <strong style={{ color: 'var(--accent-blue)' }}>Structure:</strong> 18 Layers with Residual (Skip) Connections to solve vanishing gradients.
                                </li>
                                <li>
                                    <strong style={{ color: 'var(--accent-blue)' }}>Efficiency:</strong> High accuracy balance with moderate computational cost.
                                </li>
                            </ul>
                        </div>
                        <div style={{ flex: 1, minWidth: '300px', background: 'rgba(0,0,0,0.3)', padding: '20px', borderRadius: '8px' }}>
                            <h4 style={{ fontSize: '1rem', color: 'var(--accent-green)', marginBottom: '15px', fontFamily: 'var(--terminal-font)' }}>
                                // HOW_IT_WORKS_LOG
                            </h4>
                            <div style={{ fontSize: '0.9rem', color: '#ccc', fontFamily: 'monospace' }}>
                                <p>1. [INPUT] Image is divided into pixels.</p>
                                <p>2. [CONV] Layers extract raw features (edges, textures).</p>
                                <p>3. [SKIP] Residual connections pass info forward.</p>
                                <p>4. [BACKPROP] Weights optimize via gradient descent.</p>
                                <p>5. [LOOP] Training repeats... Model converges.</p>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Interactive Scanner */}
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(350px, 1fr))', gap: '40px' }}>

                    {/* Left: Input & Display */}
                    <div>
                        <h3 style={{ fontSize: '1.2rem', marginBottom: '20px', color: '#fff' }}>[ 01 ] IMAGE_INPUT_BUFFER</h3>

                        <div
                            className="glass-card"
                            style={{
                                height: '400px',
                                display: 'flex',
                                flexDirection: 'column',
                                alignItems: 'center',
                                justifyContent: 'center',
                                border: '2px dashed rgba(0, 210, 255, 0.3)',
                                position: 'relative',
                                overflow: 'hidden'
                            }}
                        >
                            {!selectedImage ? (
                                <>
                                    <input
                                        type="file"
                                        accept="image/*"
                                        ref={fileInputRef}
                                        style={{ display: 'none' }}
                                        onChange={handleImageUpload}
                                    />
                                    <button
                                        onClick={() => fileInputRef.current.click()}
                                        className="robotic-btn"
                                        style={{
                                            padding: '20px 40px',
                                            fontSize: '1rem',
                                            fontWeight: 800,
                                            background: 'var(--accent-blue)',
                                            border: 'none',
                                            color: '#000',
                                            borderRadius: '4px',
                                            cursor: 'pointer',
                                            boxShadow: '0 0 20px var(--accent-blue)'
                                        }}
                                    >
                                        + UPLOAD_SOURCE_IMG
                                    </button>
                                    <p style={{ marginTop: '20px', color: 'var(--text-secondary)', fontSize: '0.8rem' }}>
                                        Format: .JPG, .PNG | Logic: Pixel-wise Convolution
                                    </p>
                                </>
                            ) : (
                                <>
                                    <img
                                        src={selectedImage.src}
                                        alt="Analysis Target"
                                        style={{ width: '100%', height: '100%', objectFit: 'contain', opacity: scanning ? 0.6 : 1 }}
                                    />

                                    {/* Scanning Overlay */}
                                    {scanning && (
                                        <div style={{
                                            position: 'absolute',
                                            top: 0,
                                            left: 0,
                                            width: '100%',
                                            height: '5px',
                                            background: 'var(--accent-green)',
                                            boxShadow: '0 0 20px var(--accent-green)',
                                            animation: 'scanImage 2s linear infinite'
                                        }}></div>
                                    )}

                                    {/* Grid Overlay */}
                                    <div style={{
                                        position: 'absolute',
                                        top: 0, left: 0, width: '100%', height: '100%',
                                        backgroundImage: 'linear-gradient(rgba(0, 210, 255, 0.1) 1px, transparent 1px), linear-gradient(90deg, rgba(0, 210, 255, 0.1) 1px, transparent 1px)',
                                        backgroundSize: '40px 40px',
                                        pointerEvents: 'none',
                                        zIndex: 2
                                    }}></div>

                                    {!scanning && !result && (
                                        <div style={{ position: 'absolute', bottom: '20px', zIndex: 10 }}>
                                            <button
                                                onClick={startAnalysis}
                                                className="robotic-btn"
                                                style={{
                                                    padding: '15px 30px',
                                                    background: 'rgba(0,0,0,0.8)',
                                                    border: '1px solid var(--accent-green)',
                                                    color: 'var(--accent-green)',
                                                    fontWeight: 900,
                                                    borderRadius: '4px',
                                                    cursor: 'pointer',
                                                    boxShadow: '0 0 15px var(--accent-green)'
                                                }}
                                            >
                                                INITIALIZE_SCAN
                                            </button>
                                        </div>
                                    )}
                                </>
                            )}
                        </div>
                    </div>

                    {/* Right: Analysis & Results */}
                    <div>
                        <h3 style={{ fontSize: '1.2rem', marginBottom: '20px', color: '#fff' }}>[ 02 ] NEURAL_PROCESS_LOG</h3>

                        <div className="glass-card" style={{ height: '400px', padding: '20px', fontFamily: 'monospace', position: 'relative' }}>
                            {!scanning && !result && (
                                <div style={{ color: 'var(--text-secondary)', textAlign: 'center', marginTop: '140px' }}>
                                    WAITING FOR INPUT STREAM...
                                </div>
                            )}

                            {scanning && (
                                <div style={{ color: 'var(--accent-blue)' }}>
                                    <p>{'>'} LAYER_01 [CONV2D] ... OK</p>
                                    <p>{'>'} LAYER_02 [BATCH_NORM] ... OK</p>
                                    <p>{'>'} LAYER_03 [RELU] ... ACTIVATED</p>
                                    <p>{'>'} EXTRACTING FEATURES: {scanProgress}%</p>
                                    <div style={{ width: '100%', height: '4px', background: 'rgba(255,255,255,0.1)', marginTop: '10px' }}>
                                        <div style={{ width: `${scanProgress}%`, height: '100%', background: 'var(--accent-blue)' }}></div>
                                    </div>
                                    {scanProgress > 30 && <p>{'>'} RESIDUAL_BLOCK_1 ... SKIPPING CONNECTION</p>}
                                    {scanProgress > 60 && <p>{'>'} RESIDUAL_BLOCK_2 ... MERGING GRADIENTS</p>}
                                    {scanProgress > 80 && <p>{'>'} FLATTENING OUTPUT TENSORS...</p>}
                                </div>
                            )}

                            {result && (
                                <div className="fade-in">
                                    <h4 style={{ color: 'var(--accent-green)', fontSize: '1.2rem', marginBottom: '20px', borderBottom: '1px solid rgba(255,255,255,0.1)', paddingBottom: '10px' }}>
                                        ANALYSIS_COMPLETE
                                    </h4>

                                    <div style={{ marginBottom: '20px' }}>
                                        <p style={{ color: 'var(--text-secondary)', fontSize: '0.8rem' }}>Processing Energy</p>
                                        <p style={{ fontSize: '1.8rem', fontWeight: 800, color: '#fff' }}>
                                            {result.energy} <span style={{ fontSize: '1rem', color: 'var(--text-muted)' }}>Joules</span>
                                        </p>
                                    </div>

                                    <div style={{ marginBottom: '20px' }}>
                                        <p style={{ color: 'var(--text-secondary)', fontSize: '0.8rem' }}>CO₂ Emissions Generated</p>
                                        <p style={{ fontSize: '2.5rem', fontWeight: 800, color: 'var(--accent-orange)' }}>
                                            {result.co2} <span style={{ fontSize: '1rem', color: 'var(--text-muted)' }}>gCO₂</span>
                                        </p>
                                    </div>

                                    <div style={{ padding: '15px', background: 'rgba(5, 5, 8, 0.5)', borderRadius: '4px', border: '1px solid var(--accent-blue)' }}>
                                        <p style={{ margin: 0, fontSize: '0.85rem', color: 'var(--accent-blue)' }}>
                                            IMPACT ASSESSMENT: LOW
                                        </p>
                                        <p style={{ margin: '5px 0 0 0', fontSize: '0.75rem', color: 'var(--text-secondary)' }}>
                                            ResNet-18 is highly efficient for this image dimension. Scaling to ResNet-50 would increase emissions by ~2.8x.
                                        </p>
                                    </div>
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>

            <style>{`
                @keyframes scanImage {
                    0% { top: 0%; }
                    100% { top: 100%; }
                }
            `}</style>
        </div>
    );
}

export default ResNetAnalysisPage;
